import { Schema } from "effect"

// Branded IDs
export const TxHash = Schema.String.pipe(Schema.brand("@Falcon/TxHash"))
export type TxHash = Schema.Schema.Type<typeof TxHash>

export const ContractAddress = Schema.String.pipe(Schema.brand("@Falcon/ContractAddress"))
export type ContractAddress = Schema.Schema.Type<typeof ContractAddress>

// Domain types
export interface FalconKeypair {
  readonly secretKey: Uint8Array
  readonly verifyingKey: Uint8Array
  readonly publicKeyNtt: Int32Array // h polynomial, 512 coefficients
}

export interface FalconSignatureResult {
  readonly signature: Uint8Array
  readonly salt: Uint8Array
}

export interface PackedPublicKey {
  readonly slots: ReadonlyArray<string> // 29 hex strings (felt252)
}

export type VerificationStep =
  | { step: "idle" }
  | { step: "generating-keypair" }
  | { step: "signing" }
  | { step: "creating-hint" }
  | { step: "packing" }
  | { step: "verifying"; substep: string }
  | { step: "complete"; valid: boolean; durationMs: number }
  | { step: "error"; message: string }

export interface PipelineStep {
  readonly id: string
  readonly name: string
  readonly description: string
  readonly input: string
  readonly output: string
  readonly stepCount: number
  readonly status: "pending" | "active" | "complete"
}

/**
 * Tests for WasmRuntime — effect-services category (ES-003).
 *
 * Strategy:
 * 1. Unit tests for isValidWasmModule (runtime type guard) — validate that it
 *    correctly rejects null, missing methods, wrong types, and accepts a full
 *    conformant WasmModule object.
 * 2. Integration tests: inject a mock WasmModule via Layer.succeed and verify
 *    every method is callable without loading the real WASM binary.
 * 3. Integration test for WasmRuntimeLive failure: in the Bun/Node test
 *    environment /wasm/falcon_rs.js cannot be resolved, so the live Layer must
 *    fail cleanly with a WasmLoadError.
 *
 * Coverage requirements per ES-003:
 *  - isValidWasmModule returns false for null, missing methods, wrong types
 *  - isValidWasmModule returns true for a fully-conforming mock module
 *  - WasmRuntimeLive fails with WasmLoadError when WASM cannot be loaded
 *  - A mock layer can be successfully injected and consumed by an Effect
 *
 * Test runner: bun test
 */

import { describe, it, expect } from "bun:test"
import { Effect, Exit, Layer, Cause } from "effect"
import {
  WasmRuntime,
  WasmRuntimeLive,
  isValidWasmModule,
} from "../WasmRuntime"
import type { WasmModule } from "../WasmRuntime"
import { WasmLoadError } from "../errors"

// ---------------------------------------------------------------------------
// Mock WasmModule factory
// ---------------------------------------------------------------------------

/** Creates a fully-conformant WasmModule with all required methods. */
const makeMockWasmModule = (): WasmModule => ({
  keygen: (_seed: Uint8Array) => ({ sk: new Uint8Array(0), vk: new Uint8Array(0) }),
  sign: (_sk: Uint8Array, _msg: Uint8Array, _salt: Uint8Array) => ({
    signature: new Uint8Array(0),
    salt: new Uint8Array(0),
  }),
  verify: (_vk: Uint8Array, _msg: Uint8Array, _sig: Uint8Array) => true,
  create_verification_hint: (_s1: Int32Array, _pkNtt: Int32Array) =>
    new Uint16Array(0),
  pack_public_key_wasm: (_pkNtt: Uint16Array) => [],
  public_key_length: () => 897,
  salt_length: () => 40,
})

// ---------------------------------------------------------------------------
// Unit tests: isValidWasmModule
// ---------------------------------------------------------------------------

describe("isValidWasmModule", () => {
  it("returns false for null", () => {
    expect(isValidWasmModule(null)).toBe(false)
  })

  it("returns false for undefined", () => {
    expect(isValidWasmModule(undefined)).toBe(false)
  })

  it("returns false for a number", () => {
    expect(isValidWasmModule(42)).toBe(false)
  })

  it("returns false for a string", () => {
    expect(isValidWasmModule("wasm")).toBe(false)
  })

  it("returns false for an empty object", () => {
    expect(isValidWasmModule({})).toBe(false)
  })

  it("returns false when keygen is missing", () => {
    const { keygen: _keygen, ...rest } = makeMockWasmModule()
    expect(isValidWasmModule(rest)).toBe(false)
  })

  it("returns false when sign is missing", () => {
    const { sign: _sign, ...rest } = makeMockWasmModule()
    expect(isValidWasmModule(rest)).toBe(false)
  })

  it("returns false when verify is missing", () => {
    const { verify: _verify, ...rest } = makeMockWasmModule()
    expect(isValidWasmModule(rest)).toBe(false)
  })

  it("returns false when create_verification_hint is missing", () => {
    const { create_verification_hint: _, ...rest } = makeMockWasmModule()
    expect(isValidWasmModule(rest)).toBe(false)
  })

  it("returns false when pack_public_key_wasm is missing", () => {
    const { pack_public_key_wasm: _, ...rest } = makeMockWasmModule()
    expect(isValidWasmModule(rest)).toBe(false)
  })

  it("returns false when public_key_length is missing", () => {
    const { public_key_length: _, ...rest } = makeMockWasmModule()
    expect(isValidWasmModule(rest)).toBe(false)
  })

  it("returns false when salt_length is missing", () => {
    const { salt_length: _, ...rest } = makeMockWasmModule()
    expect(isValidWasmModule(rest)).toBe(false)
  })

  it("returns false when keygen is a string instead of a function", () => {
    const mod = { ...makeMockWasmModule(), keygen: "not-a-function" }
    expect(isValidWasmModule(mod)).toBe(false)
  })

  it("returns false when verify is a number instead of a function", () => {
    const mod = { ...makeMockWasmModule(), verify: 42 }
    expect(isValidWasmModule(mod)).toBe(false)
  })

  it("returns false when sign is null instead of a function", () => {
    const mod = { ...makeMockWasmModule(), sign: null }
    expect(isValidWasmModule(mod)).toBe(false)
  })

  it("returns true for a complete valid WasmModule", () => {
    expect(isValidWasmModule(makeMockWasmModule())).toBe(true)
  })
})

// ---------------------------------------------------------------------------
// Integration tests: Layer.succeed injection
// ---------------------------------------------------------------------------

/** Helper: run an effect with WasmRuntime provided by a Layer. */
async function runWithWasm<A, E>(
  effect: Effect.Effect<A, E, WasmRuntime>,
  layer: Layer.Layer<WasmRuntime>,
): Promise<Exit.Exit<A, E>> {
  return Effect.runPromiseExit(effect.pipe(Effect.provide(layer)))
}

describe("WasmRuntime Layer injection (mock)", () => {
  it("resolves mock WasmModule via Layer.succeed", async () => {
    const layer = Layer.succeed(WasmRuntime, makeMockWasmModule())
    const exit = await runWithWasm(
      Effect.gen(function* () {
        const wasm = yield* WasmRuntime
        return wasm.public_key_length()
      }),
      layer,
    )
    expect(Exit.isSuccess(exit)).toBe(true)
    if (Exit.isSuccess(exit)) {
      expect(exit.value).toBe(897)
    }
  })

  it("resolves salt_length from the injected module", async () => {
    const layer = Layer.succeed(WasmRuntime, makeMockWasmModule())
    const exit = await runWithWasm(
      Effect.gen(function* () {
        const wasm = yield* WasmRuntime
        return wasm.salt_length()
      }),
      layer,
    )
    expect(Exit.isSuccess(exit)).toBe(true)
    if (Exit.isSuccess(exit)) {
      expect(exit.value).toBe(40)
    }
  })

  it("calls keygen through the injected Layer", async () => {
    const layer = Layer.succeed(WasmRuntime, makeMockWasmModule())
    const exit = await runWithWasm(
      Effect.gen(function* () {
        const wasm = yield* WasmRuntime
        return wasm.keygen(new Uint8Array(32))
      }),
      layer,
    )
    expect(Exit.isSuccess(exit)).toBe(true)
    if (Exit.isSuccess(exit)) {
      expect(exit.value).toHaveProperty("sk")
      expect(exit.value).toHaveProperty("vk")
    }
  })

  it("calls sign through the injected Layer", async () => {
    const layer = Layer.succeed(WasmRuntime, makeMockWasmModule())
    const exit = await runWithWasm(
      Effect.gen(function* () {
        const wasm = yield* WasmRuntime
        return wasm.sign(new Uint8Array(0), new Uint8Array(0), new Uint8Array(0))
      }),
      layer,
    )
    expect(Exit.isSuccess(exit)).toBe(true)
    if (Exit.isSuccess(exit)) {
      expect(exit.value).toHaveProperty("signature")
      expect(exit.value).toHaveProperty("salt")
    }
  })

  it("calls verify through the injected Layer and returns a boolean", async () => {
    const layer = Layer.succeed(WasmRuntime, makeMockWasmModule())
    const exit = await runWithWasm(
      Effect.gen(function* () {
        const wasm = yield* WasmRuntime
        return wasm.verify(
          new Uint8Array(0),
          new Uint8Array(0),
          new Uint8Array(0),
        )
      }),
      layer,
    )
    expect(Exit.isSuccess(exit)).toBe(true)
    if (Exit.isSuccess(exit)) {
      expect(typeof exit.value).toBe("boolean")
    }
  })

  it("calls pack_public_key_wasm through the injected Layer", async () => {
    const layer = Layer.succeed(WasmRuntime, makeMockWasmModule())
    const exit = await runWithWasm(
      Effect.gen(function* () {
        const wasm = yield* WasmRuntime
        return wasm.pack_public_key_wasm(new Uint16Array(512))
      }),
      layer,
    )
    expect(Exit.isSuccess(exit)).toBe(true)
    if (Exit.isSuccess(exit)) {
      expect(Array.isArray(exit.value)).toBe(true)
    }
  })

  it("calls create_verification_hint through the injected Layer", async () => {
    const layer = Layer.succeed(WasmRuntime, makeMockWasmModule())
    const exit = await runWithWasm(
      Effect.gen(function* () {
        const wasm = yield* WasmRuntime
        return wasm.create_verification_hint(new Int32Array(512), new Int32Array(512))
      }),
      layer,
    )
    expect(Exit.isSuccess(exit)).toBe(true)
    if (Exit.isSuccess(exit)) {
      expect(exit.value).toBeInstanceOf(Uint16Array)
    }
  })
})

// ---------------------------------------------------------------------------
// Integration test: WasmRuntimeLive fails gracefully in test environment
// ---------------------------------------------------------------------------

describe("WasmRuntimeLive", () => {
  it("fails with WasmLoadError when WASM file is absent in test environment", async () => {
    // In the Bun/Node test environment, /wasm/falcon_rs.js cannot be resolved
    // via dynamic import. The tryPromise catch handler wraps the error as
    // WasmLoadError so the failure is always typed, never a raw exception.
    const exit = await Effect.runPromiseExit(
      Effect.gen(function* () {
        return yield* WasmRuntime
      }).pipe(Effect.provide(WasmRuntimeLive)),
    )

    expect(Exit.isFailure(exit)).toBe(true)
    if (Exit.isFailure(exit)) {
      const causeStr = JSON.stringify(exit.cause)
      expect(causeStr).toContain("WasmLoadError")
    }
  })

  it("WasmLoadError from live Layer can be caught with catchTag", async () => {
    let caught = false
    let caughtMessage = ""

    await Effect.runPromise(
      Effect.gen(function* () {
        return yield* WasmRuntime
      }).pipe(
        Effect.provide(WasmRuntimeLive),
        Effect.catchTag("WasmLoadError", (e) => {
          caught = true
          caughtMessage = e.message
          return Effect.succeed(null)
        }),
      ),
    )

    expect(caught).toBe(true)
    expect(caughtMessage.length).toBeGreaterThan(0)
  })
})

// ---------------------------------------------------------------------------
// Structural / architecture tests
// ---------------------------------------------------------------------------

describe("WasmRuntime architecture", () => {
  it("WasmLoadError has _tag 'WasmLoadError'", () => {
    const err = new WasmLoadError({ message: "test" })
    expect(err._tag).toBe("WasmLoadError")
    expect(err.message).toBe("test")
  })

  it("WasmRuntime Tag has key 'WasmRuntime'", () => {
    expect(WasmRuntime.key).toBe("WasmRuntime")
  })
})

/**
 * Tests for verify-playground Schema.TaggedError classes.
 *
 * Coverage requirements:
 * - Every Schema.TaggedError must be constructable and matchable
 * - _tag must equal the class name string
 */

import { describe, it, expect } from "bun:test"
import { Effect, Exit, Cause } from "effect"
import {
  WasmLoadError,
  KeygenError,
  SigningError,
  VerificationError,
  HintGenerationError,
  PackingError,
} from "../../services/errors"

describe("WasmLoadError", () => {
  it("is constructable with a message", () => {
    const err = new WasmLoadError({ message: "failed to load wasm" })
    expect(err.message).toBe("failed to load wasm")
    expect(err._tag).toBe("WasmLoadError")
  })

  it("can be used as Effect failure and matched by _tag", async () => {
    const effect = Effect.fail(
      new WasmLoadError({ message: "module missing" }),
    )
    const exit = await Effect.runPromiseExit(effect)
    expect(Exit.isFailure(exit)).toBe(true)
    if (Exit.isFailure(exit)) {
      const err = Cause.failureOption(exit.cause)
      expect(err._tag).toBe("Some")
      // @ts-expect-error — Option.Some wraps the error
      expect(err.value._tag).toBe("WasmLoadError")
      // @ts-expect-error
      expect(err.value.message).toBe("module missing")
    }
  })

  it("can be caught with catchTag", async () => {
    let caught = false
    const effect = Effect.fail(
      new WasmLoadError({ message: "oops" }),
    ).pipe(
      Effect.catchTag("WasmLoadError", () => {
        caught = true
        return Effect.succeed("recovered")
      }),
    )
    const result = await Effect.runPromise(effect)
    expect(result).toBe("recovered")
    expect(caught).toBe(true)
  })
})

describe("KeygenError", () => {
  it("is constructable with a message", () => {
    const err = new KeygenError({ message: "keygen failed" })
    expect(err.message).toBe("keygen failed")
    expect(err._tag).toBe("KeygenError")
  })

  it("roundtrips through Effect failure", async () => {
    const exit = await Effect.runPromiseExit(
      Effect.fail(new KeygenError({ message: "seed error" })),
    )
    expect(Exit.isFailure(exit)).toBe(true)
    if (Exit.isFailure(exit)) {
      const err = Cause.failureOption(exit.cause)
      // @ts-expect-error
      expect(err.value._tag).toBe("KeygenError")
    }
  })
})

describe("SigningError", () => {
  it("is constructable with a message", () => {
    const err = new SigningError({ message: "signing failed" })
    expect(err.message).toBe("signing failed")
    expect(err._tag).toBe("SigningError")
  })

  it("roundtrips through Effect failure", async () => {
    const exit = await Effect.runPromiseExit(
      Effect.fail(new SigningError({ message: "sig err" })),
    )
    expect(Exit.isFailure(exit)).toBe(true)
  })
})

describe("VerificationError", () => {
  it("is constructable with message and step", () => {
    const err = new VerificationError({
      message: "norm check failed",
      step: "norm-check",
    })
    expect(err.message).toBe("norm check failed")
    expect(err.step).toBe("norm-check")
    expect(err._tag).toBe("VerificationError")
  })

  it("can be caught by _tag", async () => {
    let caughtStep = ""
    await Effect.runPromise(
      Effect.fail(
        new VerificationError({ message: "bad sig", step: "verify" }),
      ).pipe(
        Effect.catchTag("VerificationError", (e) => {
          caughtStep = e.step
          return Effect.succeed(null)
        }),
      ),
    )
    expect(caughtStep).toBe("verify")
  })
})

describe("HintGenerationError", () => {
  it("is constructable with a message", () => {
    const err = new HintGenerationError({ message: "hint failed" })
    expect(err.message).toBe("hint failed")
    expect(err._tag).toBe("HintGenerationError")
  })

  it("fails the effect on failure", async () => {
    const exit = await Effect.runPromiseExit(
      Effect.fail(new HintGenerationError({ message: "ntt error" })),
    )
    expect(Exit.isFailure(exit)).toBe(true)
    expect(Exit.isSuccess(exit)).toBe(false)
  })
})

describe("PackingError", () => {
  it("is constructable with a message", () => {
    const err = new PackingError({ message: "pack failed" })
    expect(err.message).toBe("pack failed")
    expect(err._tag).toBe("PackingError")
  })

  it("fails the effect on failure", async () => {
    const exit = await Effect.runPromiseExit(
      Effect.fail(new PackingError({ message: "slots error" })),
    )
    expect(Exit.isFailure(exit)).toBe(true)
  })
})

/**
 * Tests for Starknet-specific Schema.TaggedError classes.
 *
 * Coverage requirements:
 * - Every Schema.TaggedError must be constructable and matchable
 * - _tag must equal the class name string
 * - Errors must roundtrip through Effect failure/exit
 */

import { describe, it, expect } from "bun:test"
import { Effect, Exit, Cause } from "effect"
import {
  StarknetRpcError,
  AccountDeployError,
  InsufficientFundsError,
} from "../../services/errors"

describe("StarknetRpcError", () => {
  it("is constructable with message and code", () => {
    const err = new StarknetRpcError({
      message: "RPC call failed",
      code: -32000,
    })
    expect(err.message).toBe("RPC call failed")
    expect(err.code).toBe(-32000)
    expect(err._tag).toBe("StarknetRpcError")
  })

  it("roundtrips through Effect.runPromiseExit", async () => {
    const exit = await Effect.runPromiseExit(
      Effect.fail(new StarknetRpcError({ message: "connection refused", code: -1 })),
    )
    expect(Exit.isFailure(exit)).toBe(true)
    expect(Exit.isSuccess(exit)).toBe(false)
    if (Exit.isFailure(exit)) {
      const err = Cause.failureOption(exit.cause)
      expect(err._tag).toBe("Some")
      // @ts-expect-error — Option.Some wraps the error
      expect(err.value._tag).toBe("StarknetRpcError")
      // @ts-expect-error
      expect(err.value.code).toBe(-1)
    }
  })

  it("can be caught with catchTag", async () => {
    let caughtCode = 0
    await Effect.runPromise(
      Effect.fail(new StarknetRpcError({ message: "bad request", code: 400 })).pipe(
        Effect.catchTag("StarknetRpcError", (e) => {
          caughtCode = e.code
          return Effect.succeed(null)
        }),
      ),
    )
    expect(caughtCode).toBe(400)
  })

  it("_tag is 'StarknetRpcError' (not 'Error' or undefined)", () => {
    const err = new StarknetRpcError({ message: "x", code: 0 })
    expect(err._tag).toBe("StarknetRpcError")
    expect(err._tag).not.toBe("Error")
  })

  it("preserves code=0 (zero is valid, not falsy-filtered)", () => {
    const err = new StarknetRpcError({ message: "ok", code: 0 })
    expect(err.code).toBe(0)
  })
})

describe("AccountDeployError", () => {
  it("is constructable with message only (txHash optional)", () => {
    const err = new AccountDeployError({ message: "deploy failed" })
    expect(err.message).toBe("deploy failed")
    expect(err._tag).toBe("AccountDeployError")
    expect(err.txHash).toBeUndefined()
  })

  it("is constructable with message and txHash", () => {
    const err = new AccountDeployError({
      message: "tx reverted",
      txHash: "0xcafebeef",
    })
    expect(err.message).toBe("tx reverted")
    expect(err.txHash).toBe("0xcafebeef")
    expect(err._tag).toBe("AccountDeployError")
  })

  it("roundtrips through Effect.runPromiseExit", async () => {
    const exit = await Effect.runPromiseExit(
      Effect.fail(
        new AccountDeployError({ message: "nonce too low", txHash: "0xabc" }),
      ),
    )
    expect(Exit.isFailure(exit)).toBe(true)
    if (Exit.isFailure(exit)) {
      const err = Cause.failureOption(exit.cause)
      // @ts-expect-error
      expect(err.value._tag).toBe("AccountDeployError")
      // @ts-expect-error
      expect(err.value.txHash).toBe("0xabc")
    }
  })

  it("can be caught with catchTag and txHash is accessible", async () => {
    let caughtHash: string | undefined = undefined
    await Effect.runPromise(
      Effect.fail(
        new AccountDeployError({ message: "failed", txHash: "0xdeadbeef" }),
      ).pipe(
        Effect.catchTag("AccountDeployError", (e) => {
          caughtHash = e.txHash
          return Effect.succeed(null)
        }),
      ),
    )
    expect(caughtHash!).toBe("0xdeadbeef")
  })

  it("succeeds in an effect chain when no error is thrown", async () => {
    const exit = await Effect.runPromiseExit(
      Effect.succeed({ txHash: "0x123", address: "0xabc" }),
    )
    expect(Exit.isSuccess(exit)).toBe(true)
  })
})

describe("InsufficientFundsError", () => {
  it("is constructable with message, address, and required", () => {
    const err = new InsufficientFundsError({
      message: "need more ETH",
      address: "0x1234",
      required: "1000000000000000000",
    })
    expect(err.message).toBe("need more ETH")
    expect(err.address).toBe("0x1234")
    expect(err.required).toBe("1000000000000000000")
    expect(err._tag).toBe("InsufficientFundsError")
  })

  it("roundtrips through Effect.runPromiseExit", async () => {
    const exit = await Effect.runPromiseExit(
      Effect.fail(
        new InsufficientFundsError({
          message: "balance too low",
          address: "0xbeef",
          required: "500",
        }),
      ),
    )
    expect(Exit.isFailure(exit)).toBe(true)
    if (Exit.isFailure(exit)) {
      const err = Cause.failureOption(exit.cause)
      // @ts-expect-error
      expect(err.value._tag).toBe("InsufficientFundsError")
      // @ts-expect-error
      expect(err.value.address).toBe("0xbeef")
    }
  })

  it("can be caught with catchTag and address is accessible", async () => {
    let caughtAddress = ""
    await Effect.runPromise(
      Effect.fail(
        new InsufficientFundsError({
          message: "not enough",
          address: "0xfeed",
          required: "999",
        }),
      ).pipe(
        Effect.catchTag("InsufficientFundsError", (e) => {
          caughtAddress = e.address
          return Effect.succeed(null)
        }),
      ),
    )
    expect(caughtAddress).toBe("0xfeed")
  })

  it("is distinct from StarknetRpcError (different _tag)", () => {
    const rpcErr = new StarknetRpcError({ message: "x", code: 0 })
    const fundsErr = new InsufficientFundsError({
      message: "y",
      address: "0x0",
      required: "0",
    })
    expect(rpcErr._tag).not.toBe(fundsErr._tag)
    expect(fundsErr._tag).toBe("InsufficientFundsError")
  })
})
